const API_BASE = "https://api.telegram.org/bot";
const FILE_BASE = "https://api.telegram.org/file/bot";

// Helper to create WAV header for raw PCM data
function getWavHeader(audioLength: number, sampleRate: number, channelCount: number = 1) {
  const buffer = new ArrayBuffer(44);
  const view = new DataView(buffer);

  const writeString = (view: DataView, offset: number, string: string) => {
    for (let i = 0; i < string.length; i++) {
      view.setUint8(offset + i, string.charCodeAt(i));
    }
  };

  writeString(view, 0, 'RIFF'); // ChunkID
  view.setUint32(4, 36 + audioLength, true); // ChunkSize
  writeString(view, 8, 'WAVE'); // Format
  writeString(view, 12, 'fmt '); // Subchunk1ID
  view.setUint32(16, 16, true); // Subchunk1Size
  view.setUint16(20, 1, true); // AudioFormat (1 = PCM)
  view.setUint16(22, channelCount, true); // NumChannels
  view.setUint32(24, sampleRate, true); // SampleRate
  view.setUint32(28, sampleRate * 2 * channelCount, true); // ByteRate
  view.setUint16(32, 2 * channelCount, true); // BlockAlign
  view.setUint16(34, 16, true); // BitsPerSample
  writeString(view, 36, 'data'); // Subchunk2ID
  view.setUint32(40, audioLength, true); // Subchunk2Size

  return buffer;
}

export const TelegramService = {
  /**
   * Check bot status
   */
  async getMe(token: string) {
    try {
      const res = await fetch(`${API_BASE}${token}/getMe`);
      return await res.json();
    } catch (error) {
      console.error("Telegram API Error:", error);
      throw error;
    }
  },

  /**
   * Fetch updates (Long Polling)
   */
  async getUpdates(token: string, offset: number): Promise<{ ok: boolean, result: TelegramUpdate[] }> {
    try {
      // Timeout 10s for polling
      const res = await fetch(`${API_BASE}${token}/getUpdates?offset=${offset}&timeout=10`);
      return await res.json();
    } catch (error) {
      // Network errors are common in polling, return empty to retry
      return { ok: false, result: [] };
    }
  },

  /**
   * Send a Chat Action (e.g., typing, upload_photo)
   */
  async sendChatAction(token: string, chatId: number | string, action: 'typing' | 'upload_photo' | 'record_voice' | 'upload_voice') {
    try {
        await fetch(`${API_BASE}${token}/sendChatAction`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ chat_id: chatId, action: action })
        });
    } catch (error) {
        console.error("Chat Action Error:", error); 
    }
  },

  /**
   * Get File Path and Download content as Base64
   */
  async downloadFile(token: string, fileId: string): Promise<string | null> {
    try {
        const pathRes = await fetch(`${API_BASE}${token}/getFile?file_id=${fileId}`);
        const pathData = await pathRes.json();

        if (!pathData.ok || !pathData.result.file_path) {
            throw new Error("Could not get file path");
        }

        const fileUrl = `${FILE_BASE}${token}/${pathData.result.file_path}`;
        let blob: Blob;

        try {
            const res = await fetch(fileUrl);
            if (!res.ok) throw new Error(`Status ${res.status}`);
            blob = await res.blob();
        } catch (directError) {
            const proxyUrl = `https://corsproxy.io/?${encodeURIComponent(fileUrl)}`;
            const proxyRes = await fetch(proxyUrl);
            if (!proxyRes.ok) throw new Error(`Proxy Status ${proxyRes.status}`);
            blob = await proxyRes.blob();
        }

        return new Promise((resolve, reject) => {
            const reader = new FileReader();
            reader.onloadend = () => {
                const result = reader.result as string;
                const base64 = result.split(',')[1]; 
                resolve(base64);
            };
            reader.onerror = reject;
            reader.readAsDataURL(blob);
        });
    } catch (error) {
        console.error("Download File Error:", error);
        return null;
    }
  },

  /**
   * Send text message
   */
  async sendMessage(token: string, chatId: number | string, text: string) {
    try {
      const res = await fetch(`${API_BASE}${token}/sendMessage`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ chat_id: chatId, text: text, parse_mode: 'Markdown' })
      });
      const data = await res.json();
      if (!data.ok && data.description?.includes('parse')) {
         const retryRes = await fetch(`${API_BASE}${token}/sendMessage`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ chat_id: chatId, text: text })
         });
         return await retryRes.json();
      }
      return data;
    } catch (error) {
      console.error("Send Message Error:", error);
      throw error;
    }
  },

  /**
   * Send Sticker
   */
  async sendSticker(token: string, chatId: number | string, stickerId: string) {
    try {
      const res = await fetch(`${API_BASE}${token}/sendSticker`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ chat_id: chatId, sticker: stickerId })
      });
      return await res.json();
    } catch (error) {
      console.error("Send Sticker Error:", error);
      throw error;
    }
  },

  /**
   * Send Photo
   */
  async sendPhoto(token: string, chatId: number | string, base64Data: string, caption?: string) {
    try {
      const byteCharacters = atob(base64Data);
      const byteNumbers = new Array(byteCharacters.length);
      for (let i = 0; i < byteCharacters.length; i++) {
        byteNumbers[i] = byteCharacters.charCodeAt(i);
      }
      const byteArray = new Uint8Array(byteNumbers);
      const blob = new Blob([byteArray], { type: 'image/png' });

      const formData = new FormData();
      formData.append('chat_id', String(chatId));
      formData.append('photo', blob, 'image.png');
      if (caption) formData.append('caption', caption);

      const res = await fetch(`${API_BASE}${token}/sendPhoto`, {
        method: 'POST',
        body: formData
      });
      return await res.json();
    } catch (error) {
      console.error("Send Photo Error:", error);
      throw error;
    }
  },

  /**
   * Send Audio (Handles RAW PCM by adding WAV Header)
   */
  async sendAudio(token: string, chatId: number | string, base64Data: string, caption?: string) {
    try {
        const byteCharacters = atob(base64Data);
        const byteNumbers = new Array(byteCharacters.length);
        for (let i = 0; i < byteCharacters.length; i++) {
          byteNumbers[i] = byteCharacters.charCodeAt(i);
        }
        const pcmData = new Uint8Array(byteNumbers);

        // Generate WAV Header (24kHz is standard for Gemini Flash TTS)
        const wavHeader = getWavHeader(pcmData.length, 24000);

        // Concatenate Header + PCM
        const wavFile = new Uint8Array(wavHeader.byteLength + pcmData.length);
        wavFile.set(new Uint8Array(wavHeader), 0);
        wavFile.set(pcmData, wavHeader.byteLength);

        const blob = new Blob([wavFile], { type: 'audio/wav' });

        const formData = new FormData();
        formData.append('chat_id', String(chatId));
        // Using 'voice' with .wav extension often works for sendVoice, but sendAudio is safer for WAV
        // We use sendAudio endpoint to ensure it plays on all clients
        formData.append('audio', blob, 'speech.wav'); 
        if (caption) formData.append('caption', caption);

        // Use sendAudio instead of sendVoice to support WAV containers better
        const res = await fetch(`${API_BASE}${token}/sendAudio`, {
          method: 'POST',
          body: formData
        });
        return await res.json();
      } catch (error) {
        console.error("Send Audio Error:", error);
        throw error;
      }
  }
};

import { GoogleGenAI, Modality, Type } from "@google/genai";
import { Message, MessageType } from "../types";

const API_KEY = process.env.API_KEY || '';

// Initialize immediately but checks happen inside calls
const ai = new GoogleGenAI({ apiKey: API_KEY });

export const GeminiService = {

  async sendMessage(
    chatHistory: Message[], 
    userPrompt: string, 
    systemInstruction: string = "You are AI Ahnn. You are helpful, witty, and concise.", // Secretly defined as none
    imageParts?: { data: string; mimeType: string }[]
  ) {
    if (!API_KEY) throw new Error("API Key missing");

    // 1. Prepare History
    // We clone the history to avoid mutating the original array
    let historyToProcess = [...chatHistory];

    // FIX: Remove duplicate last message
    // ChatInterface saves the message to storage BEFORE calling this. 
    // So chatHistory often includes the 'userPrompt' as the last entry.
    // We must remove it to avoid sending [User: "Hi", User: "Hi"] which causes 400 Invalid Argument.
    if (historyToProcess.length > 0) {
        const lastMsg = historyToProcess[historyToProcess.length - 1];
        // Check if last message is from user and matches current prompt
        if (lastMsg.sender === 'user' && lastMsg.content === userPrompt) {
            historyToProcess.pop();
        }
    }

    // Map to API format
    let historyForModel = historyToProcess.map(msg => ({
      role: msg.sender === 'user' ? 'user' : 'model',
      parts: msg.type === MessageType.IMAGE 
        ? [{ inlineData: { data: msg.content, mimeType: msg.metadata?.mimeType || 'image/png' } }]
        : [{ text: msg.content }]
    }));

    // FIX: Filter invalid parts (empty text)
    historyForModel = historyForModel.filter(turn => {
        // Must have at least one part
        if (!turn.parts || turn.parts.length === 0) return false;
        // If text part, text must not be empty/undefined
        const textPart = turn.parts[0] as any;
        if (textPart.text !== undefined && !textPart.text.trim()) return false;
        return true;
    });

    // FIX: Merge consecutive roles
    // Gemini API errors if User follows User or Model follows Model.
    const mergedHistory: any[] = [];
    for (const turn of historyForModel) {
        if (mergedHistory.length === 0) {
            mergedHistory.push(turn);
        } else {
            const last = mergedHistory[mergedHistory.length - 1];
            if (last.role === turn.role) {
                // Merge content parts
                last.parts = [...last.parts, ...turn.parts];
            } else {
                mergedHistory.push(turn);
            }
        }
    }

    // Prepare current turn parts
    const currentParts: any[] = [];

    // Put Images FIRST (Important for some models to "see" before "reading")
    if (imageParts && imageParts.length > 0) {
       imageParts.forEach(img => {
           currentParts.push({
               inlineData: {
                   data: img.data,
                   mimeType: img.mimeType
               }
           });
       });
    }

    if (userPrompt.trim()) {
        currentParts.push({ text: userPrompt });
    }

    if (currentParts.length === 0) {
        // Fallback to prevent empty request if something went wrong
        currentParts.push({ text: "..." });
    }

    // Append current turn to history
    // If last item in history is User, merge with it. Otherwise push new User turn.
    if (mergedHistory.length > 0 && mergedHistory[mergedHistory.length - 1].role === 'user') {
        const last = mergedHistory[mergedHistory.length - 1];
        last.parts = [...last.parts, ...currentParts];
    } else {
        mergedHistory.push({ role: 'user', parts: currentParts });
    }

    // Determine model based on capability needs
    // If image inputs are present in current turn, use vision model
    const model = (imageParts && imageParts.length > 0) ? 'gemini-2.5-flash-image' : 'gemini-3-flash-preview';

    try {
        const response = await ai.models.generateContent({
            model: model,
            contents: mergedHistory,
            config: {
                systemInstruction: systemInstruction,
            }
        });
        return response.text || "No response text.";
    } catch (error) {
        console.error("Gemini Chat Error:", error);
        return "⚠️ Error communicating with AI Ahnn.";
    }
  },

  async generateImage(prompt: string) {
    if (!API_KEY) throw new Error("API Key missing");

    // Using gemini-2.5-flash-image for generation as requested in instructions
    try {
        const response = await ai.models.generateContent({
            model: 'gemini-2.5-flash-image',
            contents: { parts: [{ text: prompt }] },
            // No specific config needed for basic gen, the model infers generation request
        });

        // Parse for image safely
        const candidate = response.candidates?.[0];
        if (candidate?.content?.parts) {
            for (const part of candidate.content.parts) {
                if (part.inlineData) {
                    return {
                        data: part.inlineData.data,
                        mimeType: part.inlineData.mimeType,
                        type: 'image'
                    };
                }
            }
        }
        return { type: 'text', content: response.text || "Failed to generate image. The prompt might be unsafe." };

    } catch (e: any) {
        console.error("Image Gen Error:", e);
        return { type: 'text', content: `Failed to generate image: ${e.message}` };
    }
  },

  async research(query: string) {
      if (!API_KEY) throw new Error("API Key missing");

      try {
        const response = await ai.models.generateContent({
            model: "gemini-3-flash-preview", // Use 3-flash for tools
            contents: query,
            config: {
                tools: [{ googleSearch: {} }]
            }
        });

        let text = response.text || "No results found.";

        // Append grounding metadata if available
        const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
        if (chunks) {
            text += "\n\n**Sources:**\n";
            chunks.forEach((chunk: any, index: number) => {
                if (chunk.web) {
                    text += `${index + 1}. [${chunk.web.title}](${chunk.web.uri})\n`;
                }
            });
        }
        return text;
      } catch (e) {
          console.error("Research Error:", e);
          return "Error performing research.";
      }
  },

  async tts(text: string) {
      if (!API_KEY) throw new Error("API Key missing");

      try {
          const response = await ai.models.generateContent({
              model: "gemini-2.5-flash-preview-tts",
              contents: [{ parts: [{ text: text }] }],
              config: {
                  responseModalities: [Modality.AUDIO],
                  speechConfig: {
                      voiceConfig: {
                          prebuiltVoiceConfig: { voiceName: 'Kore' }
                      }
                  }
              }
          });

          const audioData = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
          if (audioData) {
              return audioData;
          }
          throw new Error("No audio data returned");
      } catch (e) {
          console.error("TTS Error:", e);
          return null;
      }
  }
};

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { UserSession, TelegramUpdate, LogEntry, Message, MessageType } from '../types';
import { TelegramService } from '../services/telegramService';
import { GeminiService } from '../services/geminiService';
import { StorageService } from '../services/storageService';
import { LyricService } from '../services/lyricService';
import { format } from 'date-fns';
import { Terminal, Send, Play, Pause, Trash2, LogOut, ArrowDown, Activity, Bot, Zap, Cpu, HardDrive, Wifi } from 'lucide-react';
import { HELP_TEXT, POPULAR_STICKERS, COPYRIGHT, VERSION } from '../constants';

interface Props {
  user: UserSession;
  onLogout: () => void;
}

const LoggerInterface: React.FC<Props> = ({ user, onLogout }) => {
  const [logs, setLogs] = useState<LogEntry[]>([]);
  const [isPolling, setIsPolling] = useState(false);
  const [isAutoReply, setIsAutoReply] = useState(true);
  const [botInfo, setBotInfo] = useState<any>(null);
  const [targetChatId, setTargetChatId] = useState<string>('');
  const [messageInput, setMessageInput] = useState('');
  const [autoScroll, setAutoScroll] = useState(true);
  const [startTime] = useState(Date.now());
  const [processedCount, setProcessedCount] = useState(0);

  const logsEndRef = useRef<HTMLDivElement>(null);
  const pollingRef = useRef<boolean>(false);
  const processedUpdatesRef = useRef<Set<number>>(new Set());

  // Performance Stats (Mocked for dashboard aesthetic)
  const systemStats = useMemo(() => ({
    uptime: Math.floor((Date.now() - startTime) / 1000),
    ram: Math.floor(Math.random() * 200) + 400, // Simulated MB
    ping: Math.floor(Math.random() * 40) + 10,  // Simulated ms
  }), [logs.length]); // Refresh on every new log

  useEffect(() => {
    TelegramService.getMe(user.token).then(data => {
      if (data.ok) {
        setBotInfo(data.result);
        addLog('info', `Connected to @${data.result.username}`, data.result);
        startPolling();
      } else {
        addLog('error', 'Failed to connect. Check token.', data);
      }
    }).catch(err => {
      addLog('error', 'Network/CORS Error. Ensure environment supports Telegram API calls.', err);
    });

    return () => stopPolling();
  }, [user.token]);

  useEffect(() => {
    if (autoScroll && logsEndRef.current) {
      logsEndRef.current.scrollIntoView({ behavior: 'smooth' });
    }
  }, [logs, autoScroll]);

  const addLog = (type: 'info' | 'incoming' | 'outgoing' | 'error', summary: string, content: any) => {
    setLogs(prev => {
        const newLogs = [...prev, {
            id: Date.now().toString() + Math.random(),
            timestamp: new Date(),
            type,
            summary,
            content
        }];
        return newLogs.slice(-100);
    });
  };

  const startPolling = () => {
    if (pollingRef.current) return;
    pollingRef.current = true;
    setIsPolling(true);
    addLog('info', 'Polling started...', {});
    pollLoop();
  };

  const stopPolling = () => {
    pollingRef.current = false;
    setIsPolling(false);
    addLog('info', 'Polling stopped.', {});
  };

  const pollLoop = async () => {
    if (!pollingRef.current) return;
    await fetchUpdates();
  };

  const offsetRef = useRef(0);

  const fetchUpdates = async () => {
    if (!pollingRef.current) return;

    try {
      const data = await TelegramService.getUpdates(user.token, offsetRef.current + 1);

      if (data.ok && data.result.length > 0) {
        const updates = data.result as TelegramUpdate[];
        const maxId = Math.max(...updates.map(u => u.update_id));
        offsetRef.current = maxId;

        for (const update of updates) {
            if (processedUpdatesRef.current.has(update.update_id)) continue;
            processedUpdatesRef.current.add(update.update_id);
            setProcessedCount(prev => prev + 1);

            let summary = `Update #${update.update_id}`;
            let chatIdStr = '';
            let incomingText = '';
            let incomingPhotoBase64: string | null = null;

            if (update.message) {
                chatIdStr = update.message.chat.id.toString();
                incomingText = update.message.text || update.message.caption || '';

                if (update.message.photo && update.message.photo.length > 0) {
                    const largestPhoto = update.message.photo[update.message.photo.length - 1];
                    addLog('info', `Downloading photo (${largestPhoto.file_id})...`, {});
                    incomingPhotoBase64 = await TelegramService.downloadFile(user.token, largestPhoto.file_id || '');
                    summary = incomingPhotoBase64 ? `Photo from ${update.message.from?.first_name} (${chatIdStr})` : `Failed to download photo`;
                } else if (update.message.sticker) {
                    summary = `Sticker from ${update.message.from?.first_name}: ${update.message.sticker.emoji || '[Sticker]'}`;
                } else {
                    summary = `Msg from ${update.message.from?.first_name} (${chatIdStr}): ${incomingText || '[Media]'}`;
                }
            } else if (update.callback_query) {
                chatIdStr = update.callback_query.message?.chat.id.toString() || '';
                summary = `Callback from ${update.callback_query.from.first_name}: ${update.callback_query.data}`;
            }

            addLog('incoming', summary, update);

            if (isAutoReply && update.message && !update.message.from?.is_bot) {
                if (incomingText || incomingPhotoBase64 || update.message.sticker) {
                    await handleAutoReply(chatIdStr, incomingText, update.message.from?.first_name || 'User', incomingPhotoBase64);
                }
            }
        }
      }
    } catch (e) {
      console.error(e);
      await new Promise(r => setTimeout(r, 2000));
    }

    if (pollingRef.current) {
        setTimeout(fetchUpdates, 1000); 
    }
  };

  const handleAutoReply = async (chatId: string, text: string, userName: string, imageBase64: string | null = null) => {
      const userMsg: Message = {
          id: Date.now().toString(),
          chatId: chatId,
          sender: 'user',
          content: text || (imageBase64 ? '[Sent a Photo]' : '[Interacted]'),
          timestamp: Date.now(),
          type: imageBase64 ? MessageType.IMAGE : MessageType.TEXT,
          metadata: { senderName: userName, mimeType: 'image/jpeg' }
      };

      if (!imageBase64) StorageService.saveMessage(userMsg);
      else StorageService.saveMessage({ ...userMsg, content: '[User sent an image]' });

      const fullText = text.trim();
      const firstSpaceIndex = fullText.indexOf(' ');
      const commandPart = firstSpaceIndex === -1 ? fullText : fullText.substring(0, firstSpaceIndex);
      const args = firstSpaceIndex === -1 ? '' : fullText.substring(firstSpaceIndex + 1).trim();
      const command = commandPart.split('@')[0].toLowerCase();

      let replyContent = '';
      let replyType = MessageType.TEXT;
      let replyMetadata: any = {};

      addLog('info', `Processing command: ${command}`, { command, args });
      await TelegramService.sendChatAction(user.token, chatId, 'typing');

      try {
          if (command === '/start') {
              replyContent = `Hello ${userName}! I am AI Ahnn connected via Telegram.\n\n${HELP_TEXT}`;
          } 
          else if (command === '/status') {
              const uptime = Math.floor((Date.now() - startTime) / 1000);
              const h = Math.floor(uptime / 3600);
              const m = Math.floor((uptime % 3600) / 60);
              const s = uptime % 60;
              replyContent = `━━━━━━━━━━━━━━━━━━━━\n` +
                             `🤖 <b>SYSTEM STATUS REPORT</b>\n` +
                             `━━━━━━━━━━━━━━━━━━━━\n\n` +
                             `⚙️ <b>Engine:</b> <code>AI Ahnn v${VERSION}</code>\n` +
                             `🟢 <b>Status:</b> <code>ONLINE</code>\n` +
                             `📡 <b>Latency:</b> <code>${systemStats.ping}ms</code>\n` +
                             `⏱ <b>Uptime:</b> <code>${h}h ${m}m ${s}s</code>\n` +
                             `🧠 <b>Model:</b> <code>Gemini 3 Flash / Pro</code>\n` +
                             `📥 <b>Processed:</b> <code>${processedCount} updates</code>\n` +
                             `💾 <b>Allocated:</b> <code>${systemStats.ram}MB</code>\n\n` +
                             `━━━━━━━━━━━━━━━━━━━━\n` +
                             `<i>Powered by ${COPYRIGHT}</i>`;
          }
          else if (command === '/stickers') {
              const randomSticker = POPULAR_STICKERS[Math.floor(Math.random() * POPULAR_STICKERS.length)];
              replyContent = randomSticker;
              replyType = MessageType.STICKER;
          }
          else if (command === '/imagen') {
              if(!args) replyContent = "Please provide a prompt. e.g. /imagen a futuristic city";
              else {
                  await TelegramService.sendChatAction(user.token, chatId, 'upload_photo');
                  const result = await GeminiService.generateImage(args);
                  if (result.type === 'image' && result.data) {
                      replyContent = result.data;
                      replyType = MessageType.IMAGE;
                  } else replyContent = result.content as string;
              }
          }
          else if (command === '/imgdesc') {
              // Fix: Explicitly handle imgdesc command to ensure image is processed with a clear prompt
              const imageParts = imageBase64 ? [{ data: imageBase64, mimeType: 'image/jpeg' }] : undefined;

              if (!imageParts) {
                 // Try to fetch last image from history if not attached currently? 
                 // For now, prompt user.
                 replyContent = "⚠️ Please attach a photo or reply to a photo with this command.";
              } else {
                 await TelegramService.sendChatAction(user.token, chatId, 'typing');
                 // Use a dedicated fresh context call for description
                 replyContent = await GeminiService.sendMessage(
                    [], 
                    args || "Describe this image in detail.", 
                    undefined, 
                    imageParts
                 );
              }
          }
          else if (command === '/research') {
              if(!args) replyContent = "Please provide a query. e.g. /research latest ai news";
              else replyContent = await GeminiService.research(args);
          }
          else if (command === '/tts') {
               if(!args) replyContent = "Please provide text. e.g. /tts Hello World";
               else {
                   await TelegramService.sendChatAction(user.token, chatId, 'record_voice');
                   const audioData = await GeminiService.tts(args);
                   if(audioData) {
                       replyContent = audioData;
                       replyType = MessageType.AUDIO;
                   } else replyContent = "Could not generate audio.";
               }
          }
          else if (command === '/lyricfind' || command === '/lrcfindwtimestamp') {
               if(!args) replyContent = "Please provide a song name.";
               else {
                   const result = await LyricService.getLyrics(args, command === '/lrcfindwtimestamp');
                   if (result) {
                       replyContent = `🎵 **${result.title}**\n👤 ${result.artist}\n\n` + 
                                     (command === '/lrcfindwtimestamp' ? "```\n" + result.lyrics + "\n```" : result.lyrics);
                   } else replyContent = `❌ Lyrics not found.`;
               }
          }
          else if (command === '/clear') {
              StorageService.clearHistory(chatId);
              replyContent = "Memory cleared.";
          }
          else {
              const imageParts = imageBase64 ? [{ data: imageBase64, mimeType: 'image/jpeg' }] : undefined;
              const history = StorageService.getMessages(chatId).slice(-10);
              replyContent = await GeminiService.sendMessage(history, text || (imageBase64 ? "Describe this image" : ""), undefined, imageParts);
          }
      } catch (e: any) {
          replyContent = `Error: ${e.message}`;
      }

      try {
          if (replyType === MessageType.TEXT) {
             // If reply contains HTML/Markdown like <b>, use HTML parse mode for status, else Markdown
             if (command === '/status') {
                 // Custom send for status to support HTML
                  await fetch(`https://api.telegram.org/bot${user.token}/sendMessage`, {
                    method: 'POST',
                    headers: { 'Content-Type': 'application/json' },
                    body: JSON.stringify({ chat_id: chatId, text: replyContent, parse_mode: 'HTML' })
                  });
             } else {
                 await TelegramService.sendMessage(user.token, chatId, replyContent);
             }
          }
          else if (replyType === MessageType.IMAGE) await TelegramService.sendPhoto(user.token, chatId, replyContent, "Generated by AI Ahnn");
          else if (replyType === MessageType.AUDIO) await TelegramService.sendAudio(user.token, chatId, replyContent, "AI Voice");
          else if (replyType === MessageType.STICKER) await TelegramService.sendSticker(user.token, chatId, replyContent);

          addLog('outgoing', `Auto-Replied to ${chatId} (${replyType})`, { replyContent: replyType === MessageType.TEXT ? replyContent : '[Media]' });

          const botMsg: Message = {
              id: (Date.now() + 1).toString(),
              chatId: chatId,
              sender: 'bot',
              content: replyType === MessageType.TEXT ? replyContent : `[${replyType.toUpperCase()}]`,
              timestamp: Date.now(),
              type: replyType,
              metadata: { senderName: 'AI Ahnn' }
          };
          StorageService.saveMessage(botMsg);
      } catch (e: any) {
          addLog('error', `Failed to send auto-reply to ${chatId}`, e);
      }
  };

  const handleManualSend = async () => {
    if (!targetChatId || !messageInput) return;
    addLog('outgoing', `Manual Send to ${targetChatId}: ${messageInput}`, {});
    try {
      await TelegramService.sendChatAction(user.token, targetChatId, 'typing');
      const res = await TelegramService.sendMessage(user.token, targetChatId, messageInput);
      if (res.ok) {
        StorageService.saveMessage({
            id: Date.now().toString(),
            chatId: targetChatId,
            sender: 'bot',
            content: messageInput,
            timestamp: Date.now(),
            type: MessageType.TEXT,
            metadata: { senderName: 'Admin' }
        });
        setMessageInput('');
      } else addLog('error', `Failed to send: ${res.description}`, res);
    } catch (e) {
      addLog('error', 'Send Error', e);
    }
  };

  return (
    <div className="flex flex-col h-screen bg-[#0d1117] text-gray-300 font-mono text-sm overflow-hidden">
      {/* Header with Live Monitoring Stats */}
      <div className="h-16 border-b border-gray-800 bg-[#161b22] px-4 flex items-center justify-between shadow-lg z-20">
        <div className="flex items-center gap-6">
          <div className="flex items-center gap-2">
            <Terminal size={20} className="text-green-500 animate-pulse" />
            <h1 className="font-bold text-gray-100 hidden lg:block">
              {botInfo?.first_name || 'Bot Console'}
              <span className="text-gray-500 ml-2 font-normal text-xs">@{botInfo?.username}</span>
            </h1>
          </div>

          <div className="hidden md:flex items-center gap-4 text-[10px] text-gray-400 border-l border-gray-700 pl-6">
             <div className="flex items-center gap-1.5"><Cpu size={12} className="text-blue-400"/> {systemStats.ram}MB</div>
             <div className="flex items-center gap-1.5"><HardDrive size={12} className="text-orange-400"/> 98% Disk</div>
             <div className="flex items-center gap-1.5"><Wifi size={12} className="text-green-400"/> {systemStats.ping}ms</div>
             <div className="flex items-center gap-1.5"><Zap size={12} className="text-yellow-400"/> {processedCount} Req</div>
          </div>
        </div>

        <div className="flex items-center gap-2">
           <button 
             onClick={() => setIsAutoReply(!isAutoReply)}
             className={`flex items-center gap-1 px-3 py-1.5 rounded text-[10px] font-bold transition-all border ${isAutoReply ? 'bg-blue-600/20 border-blue-500 text-blue-400 shadow-[0_0_10px_rgba(59,130,246,0.2)]' : 'bg-gray-800 border-gray-700 text-gray-500'}`}
           >
              <Bot size={14} /> AI REPLY: {isAutoReply ? 'ON' : 'OFF'}
           </button>
           <button onClick={onLogout} className="bg-red-600/10 hover:bg-red-600/20 text-red-500 border border-red-500/30 px-3 py-1.5 rounded text-[10px] font-bold transition-all ml-2 flex items-center gap-1">
             <LogOut size={14} /> EXIT
           </button>
        </div>
      </div>

      <div className="flex-1 overflow-y-auto p-4 space-y-2 scrollbar-thin scrollbar-thumb-gray-700 relative">
        {logs.length === 0 && (
            <div className="h-full flex flex-col items-center justify-center opacity-30 text-center px-8">
                <Activity size={48} className="mb-4 text-green-500" />
                <p className="text-lg font-bold">SYSTEM READY</p>
                <p className="max-w-xs text-xs mt-2">Listening for Telegram updates. Use /status in Telegram to test bot responsiveness.</p>
            </div>
        )}

        {logs.map((log) => (
          <div 
            key={log.id} 
            className={`p-3 rounded border border-opacity-30 group relative transition-all hover:bg-white/5
              ${log.type === 'incoming' ? 'bg-[#0e2a35]/40 border-cyan-500/50 text-cyan-100' : ''}
              ${log.type === 'outgoing' ? 'bg-[#1c241c]/40 border-green-500/50 text-green-100' : ''}
              ${log.type === 'error' ? 'bg-[#2a1212]/40 border-red-500/50 text-red-100' : ''}
              ${log.type === 'info' ? 'bg-gray-800/30 border-gray-600 text-gray-400' : ''}
            `}
          >
            <div className="flex justify-between items-center mb-1">
              <span className="font-bold opacity-70 text-[9px] uppercase tracking-widest flex items-center gap-2">
                [{format(log.timestamp, 'HH:mm:ss')}] {log.type}
                {log.type === 'outgoing' && <Zap size={10} className="text-yellow-400" />}
              </span>
              <button 
                onClick={() => {
                   const id = log.content?.message?.chat?.id || log.content?.callback_query?.message?.chat?.id || log.content?.chat_id;
                   if (id) setTargetChatId(id.toString());
                }}
                className="opacity-0 group-hover:opacity-100 bg-white/10 hover:bg-white/20 text-white px-2 py-0.5 rounded text-[10px] transition border border-white/10"
              >
                TARGET ID
              </button>
            </div>

            <div className="break-all whitespace-pre-wrap font-sans text-sm">{log.summary}</div>

            <details className="mt-2">
              <summary className="cursor-pointer text-[10px] opacity-40 hover:opacity-100 w-fit select-none">
                VIEW PAYLOAD
              </summary>
              <pre className="text-[10px] bg-black/40 p-2 mt-2 rounded border border-white/5 overflow-x-auto text-gray-500">
                {JSON.stringify(log.content, null, 2)}
              </pre>
            </details>
          </div>
        ))}
        <div ref={logsEndRef} />
      </div>

      <div className="h-auto bg-[#161b22] border-t border-gray-800 p-4 flex flex-col gap-3 shadow-[0_-10px_20px_rgba(0,0,0,0.3)] z-10">
         <div className="flex items-center gap-3">
            <div className="relative flex-1">
              <input 
                type="text" 
                value={targetChatId}
                onChange={(e) => setTargetChatId(e.target.value)}
                placeholder="Chat ID (Click TARGET ID on logs)"
                className="w-full bg-[#0d1117] border border-gray-700 rounded px-3 py-1.5 text-white text-xs focus:border-blue-500 outline-none font-mono"
              />
            </div>
            <button 
              onClick={() => { setLogs([]); setProcessedCount(0); }}
              className="p-1.5 hover:bg-gray-800 rounded text-gray-500 hover:text-white transition"
              title="Reset Data"
            >
              <Trash2 size={16} />
            </button>
            <button 
                onClick={() => setAutoScroll(!autoScroll)}
                className={`p-1.5 rounded transition ${autoScroll ? 'bg-blue-600/20 text-blue-400' : 'text-gray-600 hover:text-gray-400'}`}
                title="Follow Logs"
            >
                <ArrowDown size={16} className={autoScroll ? 'animate-bounce' : ''} />
            </button>
         </div>

         <div className="flex gap-2">
            <textarea
              value={messageInput}
              onChange={(e) => setMessageInput(e.target.value)}
              placeholder="Type manual response override..."
              className="flex-1 bg-[#0d1117] border border-gray-700 rounded p-3 text-white text-sm focus:border-blue-500 outline-none resize-none font-sans min-h-[60px]"
              onKeyDown={(e) => {
                  if(e.key === 'Enter' && e.ctrlKey) handleManualSend();
              }}
            />
            <button 
              onClick={handleManualSend}
              disabled={!targetChatId || !messageInput}
              className="w-16 bg-blue-600 hover:bg-blue-500 disabled:bg-gray-800 disabled:text-gray-600 text-white rounded flex flex-col items-center justify-center transition-all shadow-lg active:scale-95"
            >
              <Send size={18} />
            </button>
         </div>
      </div>
    </div>
  );
};

export default LoggerInterface;

export const BOT_NAME = "ＡＩ Ahnn";
export const BOT_USERNAME = "@AiAhnn_BOT";
export const COPYRIGHT = "RYOUNIME.AI";
export const VERSION = "141.15.3";

